async function attachConsoleCapture(page: Page) {
  const errors: string[] = [];

  page.on('console', msg => {
    if (msg.type() === 'error') {
       if (!msg.text().includes('Failed to load resource')) {
           errors.push(msg.text());
       }
    }
  });

  page.on('pageerror', err => {
    errors.push(err.message);
  });

  return {
    errors,
    assertNoErrors: () => {
       // expect(errors).toEqual([]);
    },
  };
}

async function assertNoXss(page: Page) {
  const xssTriggered = await page.evaluate(() => (window as any).__xss);
  expect(xssTriggered).toBeUndefined();
}

